/**
 * Object containing helper methods for getting optimal symbol themes used
 * to create data-driven visualizations of unique values or types.
 * The [getSchemes()](https://developers.arcgis.com/javascript/latest/references/core/smartMapping/symbology/type/#getSchemes) method is used to generate symbol properties best suited to
 * the given basemap.
 *
 * @since 4.4
 */
import type Basemap from "../../Basemap.js";
import type SceneView from "../../views/SceneView.js";
import type { TypeScheme, TypeSchemes, BasemapTheme, Theme } from "./types.js";

/**
 * Returns metadata for the available themes. If a basemap is provided, returns themes that work best
 * with the given basemap.
 *
 * @param basemap - The [Esri basemap string](https://developers.arcgis.com/javascript/latest/references/core/Map/#basemap)
 *   or object that will be used with the returned theme(s).
 * @returns Returns an object containing information about the available themes for the given basemap.
 */
export function getThemes(basemap?: Basemap | string | null | undefined): Theme[];

/**
 * Returns a primary scheme and secondary schemes defining symbol properties for type-based
 * data-driven visualizations in
 * a [Layer](https://developers.arcgis.com/javascript/latest/references/core/layers/Layer/). The `basemap` parameter determines the color of the
 * graphics used to visualize each feature. The `geometryType` determines which type of symbol to return.
 *
 * @param params - The function parameters
 * @returns Returns an object containing the optimal type scheme to use for the given
 *   basemap; it also contains secondary schemes.
 * @example
 * // gets the primary scheme for the features of the given geometry type and basemap
 * let schemes = typeSchemes.getSchemes({
 *   basemap: map.basemap,
 *   geometryType: featureLayer.geometryType
 * });
 *
 * // the best default scheme for the layer and basemap
 * let primaryScheme = schemes.primaryScheme;
 */
export function getSchemes(params: GetSchemesParameters): TypeSchemes | null | undefined;

/**
 * Returns a type scheme with the provided name.
 *
 * @param params - The function parameters.
 * @returns Returns the type scheme
 *   with the given name.
 * @since 4.12
 * @example
 * // Returns the Pastel Dreams scheme
 * let galaxyBerriesScheme = typeSchemes.getSchemeByName({
 *   basemap: map.basemap,
 *   geometryType: featureLayer.geometryType,
 *   name: "Pastel Dreams"
 * });
 */
export function getSchemeByName(params: GetSchemesByNameParameters): TypeScheme | null | undefined;

/**
 * Returns an array of type schemes with the provided tags. These schemes define symbol properties for
 * data-driven visualizations in any layer that can be rendered with a [UniqueValueRenderer](https://developers.arcgis.com/javascript/latest/references/core/renderers/UniqueValueRenderer/).
 *
 * @param params - The parameters of the function.
 * @returns Returns an array of type schemes
 *   either including or excluding the provided tags.
 * @since 4.12
 * @example
 * // Returns all the red type schemes that are subdued
 * let schemes = typeSchemes.getSchemesByTag({
 *   basemap: map.basemap,
 *   geometryType: featureLayer.geometryType,
 *   includedTags: [ "types", "subdued" ]
 * });
 */
export function getSchemesByTag(params: GetSchemesByTagParameters): TypeScheme[];

/**
 * Clones a type scheme object.
 *
 * @param scheme - The type scheme object to clone.
 * @returns Returns a clone of the given type scheme object.
 * @example
 * // clones the primary scheme returned from the getSchemes() method
 * let typeScheme = primaryScheme.clone();
 */
export function cloneScheme(scheme: TypeScheme | null | undefined): TypeScheme | null | undefined;

export interface GetSchemesParameters {
  /**
   * Indicates the number of colors to include in the color ramp within the scheme.
   *
   * @since 4.31
   */
  numColors?: number | null;
  /**
   * The Esri basemap to pair with the visualization. This
   *   value indicates the best symbol colors for visualizing features against the given basemap. If you have a
   *   non-Esri basemap (e.g. a VectorTileLayer basemap with a custom style) or no basemap at all, then use the `basemapTheme` parameter
   *   instead of this parameter.
   */
  basemap?: Basemap | string | null;
  /** The geometry type of the features to visualize. | mesh */
  geometryType: "point" | "multipoint" | "polyline" | "polygon" | "mesh" | "multipatch" | null;
  /**
   * If you have a
   *   non-Esri basemap (e.g. a VectorTileLayer basemap with a custom style) or no basemap at all, use this parameter to indicate
   *   whether the background of the visualization is `light` or `dark`.
   */
  basemapTheme?: BasemapTheme | null;
  /**
   * Determines whether to return a standardized  unique value
   * scheme for point cloud class renderers (i.e. when the `CLASS_CODE` field is driving the visualization in a
   * [PointCloudLayer](https://developers.arcgis.com/javascript/latest/references/core/layers/PointCloudLayer/)), or to return the other default primary schemes
   * used in other unique value renderers generated for non-point cloud layer types.
   *
   * @default default
   */
  theme?: "default" | "point-cloud-class" | null;
  /**
   * Indicates if the size units of the scheme will be in meters.
   * This should be `true` when the scheme is intended for 3D volumetric symbology.
   * A `view` must be provided if this property is set to `true`.
   */
  worldScale?: boolean | null;
  /**
   * The SceneView instance in which the scheme
   * will be used. This property is only applicable when the scheme will be used in conjunction with 3D symbols.
   */
  view?: SceneView | null;
}

export interface GetSchemesByNameParameters extends GetSchemesParameters {
  /** The name of the scheme to retrieve. */
  name: string;
}

export interface GetSchemesByTagParameters extends GetSchemesParameters {
  /**
   * When provided, only schemes containing all the matching tags will be returned.
   *
   * **Known Tags:** light | dark | reds | yellows | oranges | greens | blues | purples | pinks | browns | grays |
   * bright | subdued | deuteranopia | protanopia | tritanopia | grayscale | types | dot-density
   */
  includedTags?: string[] | null;
  /**
   * When provided, only schemes missing all the provided tags will be returned.
   *
   * **Known Tags:** light | dark | reds | yellows | oranges | greens | blues | purples | pinks | browns | grays |
   * bright | subdued | deuteranopia | protanopia | tritanopia | grayscale | types | dot-density
   */
  excludedTags?: string[] | null;
}